import{_ as t,c as o,o as r,a1 as a}from"./chunks/framework.9hXSu8bi.js";const s="/mypatterndocs/static/%E9%A1%B9%E7%9B%AE%E4%BB%8B%E7%BB%8D.Bsn6pkYS.png",m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/帮助文档/功能介绍/项目.md","filePath":"zh/帮助文档/功能介绍/项目.md"}'),n={name:"zh/帮助文档/功能介绍/项目.md"},l=a('<h2 id="项目" tabindex="-1">项目 <a class="header-anchor" href="#项目" aria-label="Permalink to &quot;项目&quot;">​</a></h2><blockquote><p>项目页面用于管理所有监测项目，支持项目的新建、编辑、删除、子项目管理及相关配置。</p></blockquote><p><img src="'+s+'" alt="" data-fancybox="gallery"></p><h3 id="_1-项目基本信息" tabindex="-1">1. 项目基本信息 <a class="header-anchor" href="#_1-项目基本信息" aria-label="Permalink to &quot;1. 项目基本信息&quot;">​</a></h3><ul><li><strong>编号</strong>：项目的唯一标识，系统自动生成。</li><li><strong>项目名称</strong>：自定义的项目名称，用于区分不同项目。</li><li><strong>经度</strong>：项目的经度坐标。</li><li><strong>纬度</strong>：项目的纬度坐标。</li><li><strong>项目地址</strong>：项目的详细地理位置。</li><li><strong>创建时间</strong>：项目的创建日期，由系统自动记录。</li></ul><h3 id="_2-编辑项目" tabindex="-1">2. 编辑项目 <a class="header-anchor" href="#_2-编辑项目" aria-label="Permalink to &quot;2. 编辑项目&quot;">​</a></h3><ul><li><strong>新增</strong>：点击可创建新的项目。</li><li><strong>编辑</strong>：修改当前项目的名称、地址、经纬度等信息。</li><li><strong>删除</strong>：删除当前项目（若当前项目下存在子项目，需要先删除子项目）。</li><li><strong>添加子项目</strong>：在当前项目下快速新建子项目。</li><li><strong>数据联网</strong>：配置项目与外部平台的联网接入。</li><li><strong>联网数据推送记录</strong>：查看已联网数据的历史推送记录及网络连接状态。</li><li><strong>第三方传感器接入</strong>：配置非本系统的第三方传感器数据接入。</li><li><strong>地形管理</strong>：进入该项目的所有地形数据管理页面，支持查看、编辑、文件切片、下载地形、删除地形文件等功能。</li></ul>',7),i=[l];function e(_,c,g,d,h,p){return r(),o("div",null,i)}const f=t(n,[["render",e]]);export{m as __pageData,f as default};
